//const mermaidDefinitions: string[] = [];

function currentThemeIsDark(): boolean {
  return document.documentElement.getAttribute("data-theme") === "dark";
}

// Initialize mermaid
mermaid.initialize({
  startOnLoad: false,
  theme: currentThemeIsDark() ? "dark" : "default",
  securityLevel: "loose",
  fontFamily: "var(--font-sans)",
});

// --- Math pre-processing ---

const mathPlaceholders: MathPlaceholder[] = [];

function protectMath(md: string): string {
  mathPlaceholders.length = 0;
  let idx = 0;

  // Block math: $$...$$
  md = md.replace(/\$\$([\s\S]+?)\$\$/g, (_, tex: string) => {
    const id = `%%MATH_BLOCK_${idx++}%%`;
    mathPlaceholders.push({ id, tex: tex.trim(), displayMode: true });
    return id;
  });

  // Inline math: $...$
  md = md.replace(/(?<!\$)\$(?!\$)(.+?)(?<!\$)\$(?!\$)/g, (_, tex: string) => {
    const id = `%%MATH_INLINE_${idx++}%%`;
    mathPlaceholders.push({ id, tex: tex.trim(), displayMode: false });
    return id;
  });

  return md;
}

function restoreMath(html: string): string {
  for (const { id, tex, displayMode } of mathPlaceholders) {
    try {
      const rendered = katex.renderToString(tex, {
        displayMode,
        throwOnError: false,
        trust: true,
      });
      html = html.replace(id, rendered);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      html = html.replace(
        id,
        `<span class="math-error" title="${escapeHtml(message)}">${escapeHtml(tex)}</span>`,
      );
    }
  }
  return html;
}

// --- GitHub-style alerts ---

function transformAlerts(html: string): string {
  return html.replace(
    /<blockquote>\s*<p>\[!(NOTE|TIP|IMPORTANT|WARNING|CAUTION)\]\s*<br\s*\/?>\s*([\s\S]*?)<\/p>\s*<\/blockquote>/gi,
    (_, type: string, content: string) => {
      const t = type.toLowerCase();
      const icons: Record<string, string> = {
        note: "\u2139\ufe0f",
        tip: "\ud83d\udca1",
        important: "\u203c\ufe0f",
        warning: "\u26a0\ufe0f",
        caution: "\ud83d\udd34",
      };
      return `<div class="alert alert-${t}"><div class="alert-title">${icons[t] || ""} ${type.toUpperCase()}</div><div>${content}</div></div>`;
    },
  );
}

