// --- DOM post-processing ---

function enhanceHeadings(preview: HTMLElement): void {
  const headings = preview.querySelectorAll("h1, h2, h3, h4, h5, h6");
  const slugCounts: Record<string, number> = {};

  headings.forEach((h) => {
    const text = h.textContent?.trim() || "";
    let slug = slugify(text);

    if (slugCounts[slug] !== undefined) {
      slugCounts[slug]++;
      slug = `${slug}-${slugCounts[slug]}`;
    } else {
      slugCounts[slug] = 0;
    }

    h.id = slug;

    const anchor = document.createElement("a");
    anchor.className = "heading-anchor";
    anchor.href = `#${slug}`;
    anchor.textContent = "#";
    h.appendChild(anchor);
  });
}

function enhanceCodeBlocks(preview: HTMLElement): void {
  preview.querySelectorAll("pre > code").forEach((code) => {
    const pre = code.parentElement!;
    if (pre.querySelector(".copy-btn")) return;

    const langMatch = code.className.match(/language-(\S+)/);
    const lang = langMatch ? langMatch[1] : "";

    if (lang) {
      const badge = document.createElement("span");
      badge.className = "code-lang";
      badge.textContent = lang;
      pre.insertBefore(badge, code);
    }

    const btn = document.createElement("button");
    btn.className = "copy-btn";
    btn.title = "Copy code";
    btn.textContent = "\u29c9";
    btn.addEventListener("click", () => {
      navigator.clipboard.writeText(code.textContent || "").then(() => {
        btn.classList.add("copied");
        btn.textContent = "\u2713";
        setTimeout(() => {
          btn.classList.remove("copied");
          btn.textContent = "\u29c9";
        }, 1500);
      });
    });
    pre.insertBefore(btn, code);
  });
}

async function renderMermaidBlocks(preview: HTMLElement): Promise<void> {
  const mermaidBlocks = preview.querySelectorAll("code.language-mermaid");
  if (mermaidBlocks.length === 0) return;

  mermaid.initialize({
    startOnLoad: false,
    theme: currentThemeIsDark() ? "dark" : "default",
    securityLevel: "loose",
    fontFamily: "var(--font-sans)",
  });

  for (const code of mermaidBlocks) {
    const pre = code.parentElement!;
    const graphDef = code.textContent || "";
    const id = `mermaid-graph-${mermaidId++}`;

    try {
      const { svg } = await mermaid.render(id, graphDef);
      const wrapper = document.createElement("div");
      wrapper.className = "mermaid-diagram";
      wrapper.innerHTML = svg;
      pre.replaceWith(wrapper);
    } catch (err) {
      console.warn("Mermaid render error:", err);
      const errDiv = document.createElement("div");
      errDiv.className = "mermaid-error";
      errDiv.textContent = `Mermaid error: ${err instanceof Error ? err.message : String(err)}`;
      pre.replaceWith(errDiv);
    }
  }
}

// --- Main render function ---

export function renderMarkdown(
  editorValue: string,
  preview: HTMLElement,
): void {
  let md = editorValue;

  try {
    md = protectMath(md);
    let html = marked.parse(md) as string;
    html = restoreMath(html);
    html = transformAlerts(html);
    html = DOMPurify.sanitize(html, PURIFY_CONFIG);

    preview.innerHTML = html;

    enhanceHeadings(preview);
    enhanceCodeBlocks(preview);
    renderMermaidBlocks(preview);

    // Syntax highlight (skip mermaid blocks)
    preview
      .querySelectorAll('pre code[class*="language-"]:not(.language-mermaid)')
      .forEach((block) => {
        Prism.highlightElement(block as HTMLElement);
      });

    // Handle hash navigation
    if (location.hash) {
      const target = document.getElementById(location.hash.slice(1));
      if (target) {
        setTimeout(
          () => target.scrollIntoView({ behavior: "smooth", block: "start" }),
          100,
        );
      }
    }
  } catch (err) {
    console.error("Render error:", err);
    const message = err instanceof Error ? err.message : String(err);
    preview.innerHTML = `<div style="color:var(--danger);padding:20px;font-family:var(--font-mono);font-size:var(--fs-sm);">Render error: ${escapeHtml(message)}</div>`;
  }
}
